.cortv2 .member-card{width:100%;max-width:360px;aspect-ratio:1.586;background:linear-gradient(135deg,#111 0%,#050505 100%);border:1.5px solid var(--accent);border-radius:18px;padding:26px 28px;display:flex;flex-direction:column;justify-content:space-between;box-shadow:0 0 44px rgba(255,234,0,.22),0 0 110px rgba(255,234,0,.08),10px 10px 0 rgba(255,234,0,.85);transform:rotate(-2deg)}
.cortv2 .member-card-brand{font-size:24px;font-weight:900;letter-spacing:-.04em;color:#fff;line-height:1}
.cortv2 .member-card-brand span{display:inline-block;width:8px;height:8px;background:var(--accent);border-radius:50%;margin-left:2px}
.cortv2 .member-card-top{display:flex;justify-content:space-between;align-items:flex-start}
.cortv2 .member-card-chip{font-size:10px;font-weight:800;letter-spacing:.18em;text-transform:uppercase;color:#000;background:var(--accent);padding:4px 10px;border-radius:100px}
.cortv2 .member-card-name{font-size:15px;font-weight:700;letter-spacing:.04em;text-transform:uppercase;color:rgba(255,255,255,.85)}
.cortv2 .member-card-meta{display:flex;justify-content:space-between;align-items:flex-end;margin-top:6px}
.cortv2 .member-card-num{font-size:12px;font-weight:600;letter-spacing:.16em;color:rgba(255,255,255,.82)}
.cortv2 .member-card-since{font-size:10px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,.82)}
.cortv2 .tier-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;max-width:880px;margin:0 auto 40px;text-align:left}
.cortv2 .tier-card{background:#0d0d0d;border:1.5px solid var(--accent);box-shadow:0 0 22px rgba(255,234,0,.22),0 0 56px rgba(255,234,0,.08);border-radius:14px;padding:28px 26px}
.cortv2 .tier-name{font-size:12px;font-weight:800;letter-spacing:.18em;text-transform:uppercase;color:var(--accent);margin-bottom:12px}
.cortv2 .tier-price{font-size:30px;font-weight:900;letter-spacing:-.03em;color:#fff;line-height:1}
.cortv2 .tier-price span{font-size:14px;font-weight:600;letter-spacing:0;color:rgba(255,255,255,.82)}
.cortv2 .tier-body{margin-top:20px;padding-top:18px;border-top:1px solid #1a1a1a}
.cortv2 .tier-body-label{display:flex;align-items:baseline;gap:9px;font-size:13px;font-weight:700;color:#fff;margin-bottom:8px}
.cortv2 .tier-body-label::before{content:'◆';font-size:9px;color:var(--accent);flex-shrink:0}
.cortv2 .tier-body p{font-size:12.5px;color:rgba(255,255,255,.82);line-height:1.65}
.cortv2 .member-note{font-size:12px;color:rgba(255,255,255,.82);margin-top:20px}
.cortv2 .partner-strip{background:#fff;border-top:1.5px solid var(--border);padding:96px 24px}
.cortv2 .partner-strip-inner{max-width:940px;margin:0 auto;display:grid;grid-template-columns:1.4fr 1fr;gap:56px;align-items:center}
.cortv2 .partner-strip-title{font-size:clamp(28px,4.5vw,42px);font-weight:900;letter-spacing:-.035em;line-height:1.05;color:#000;margin-bottom:14px}
.cortv2 .partner-strip-desc{font-size:15px;color:var(--muted);line-height:1.75;max-width:440px}
.cortv2 .partner-strip-tracks{list-style:none;margin-bottom:30px}
.cortv2 .partner-strip-tracks li{display:flex;align-items:flex-start;gap:12px;padding:12px 0;border-bottom:1px solid var(--bg);font-size:14px;color:#000;line-height:1.55}
.cortv2 .partner-strip-tracks li span:first-child{flex-shrink:0;padding-top:2px}
.cortv2 .partner-strip-tracks strong{font-weight:800}
.cortv2 .capture{background:#fff;padding:88px 24px;text-align:center;border-top:1.5px solid var(--border)}
.cortv2 .capture h2{font-size:clamp(26px,4vw,38px);font-weight:900;color:#000;letter-spacing:-.03em;margin-bottom:10px;display:flex;align-items:center;justify-content:center;gap:10px}
.cortv2 .cap-dot{display:inline-block;width:clamp(11px,1.4vw,16px);height:clamp(11px,1.4vw,16px);background:var(--accent);border-radius:50%;flex-shrink:0}
.cortv2 .capture p{color:var(--muted);font-size:16px;margin-bottom:36px}
.cortv2 .capture-form{display:flex;gap:10px;max-width:460px;margin:0 auto;flex-wrap:wrap;justify-content:center}
.cortv2 .capture-form input{flex:1;min-width:220px;padding:14px 22px;border-radius:100px;border:1.5px solid var(--border);background:#F2F2F2;color:#000;font-size:15px;outline:none;transition:border-color .2s;font-family:inherit}
.cortv2 .capture-form input:focus{border-color:#000}
.cortv2 .capture-form input::placeholder{color:#6a6a6a}
.cortv2 .icon{width:22px;height:22px;display:block}
.cortv2 .connector-node-icon .icon,.cortv2 .pillar-icon .icon{margin:0 auto}
.cortv2 .partner-strip-tracks .icon,.cortv2 .bundle-note .icon{width:18px;height:18px}
@keyframes cortPulse{0%,100%{opacity:1}50%{opacity:.3}}
@media (prefers-reduced-motion:no-preference){
  body.js-anim .cortv2 .reveal{opacity:0}
  body.js-anim .cortv2 .reveal.in-view{opacity:1;animation:cortRevealRise .6s ease-out backwards;animation-delay:var(--d,0s)}
  body.js-anim .cortv2 .connector-node-hub.reveal.in-view{animation-name:cortRevealHub;animation-duration:.7s}
  @keyframes cortRevealRise{from{opacity:0;transform:translateY(18px)}}
  @keyframes cortRevealHub{from{opacity:0;transform:translateY(18px) scale(.94)}}
}
.cortv2 .events-grid .event-card:nth-child(1){--d:.22s}
.cortv2 .events-grid .event-card:nth-child(2){--d:.30s}
.cortv2 .events-grid .event-card:nth-child(3){--d:.38s}
.cortv2 .pillars-grid .pillar-card:nth-child(2){--d:.08s}
.cortv2 .pillars-grid .pillar-card:nth-child(3){--d:.16s}
.cortv2 .pillars-grid .pillar-card:nth-child(4){--d:.24s}
.cortv2 .tier-grid .tier-card:nth-child(2){--d:.08s}
.cortv2 .tier-grid .tier-card:nth-child(3){--d:.16s}
.cortv2 .connector-flow>:nth-child(1){--d:0s}.cortv2 .connector-flow>:nth-child(2){--d:.07s}
.cortv2 .connector-flow>:nth-child(3){--d:.14s}.cortv2 .connector-flow>:nth-child(4){--d:.21s}
.cortv2 .connector-flow>:nth-child(5){--d:.30s}.cortv2 .connector-flow>:nth-child(6){--d:.44s}
.cortv2 .connector-flow>:nth-child(7){--d:.51s}.cortv2 .connector-flow>:nth-child(8){--d:.58s}
.cortv2 .connector-flow>:nth-child(9){--d:.65s}.cortv2 .connector-flow>:nth-child(10){--d:.72s}
.cortv2 .connector-flow>:nth-child(11){--d:.79s}
@media(max-width:1024px){.cortv2 .pillars-grid{grid-template-columns:1fr 1fr}}
@media(max-width:900px){
  .cortv2 .partner-strip-inner{grid-template-columns:1fr;gap:36px}
  .cortv2 .connector-flow{flex-direction:column;align-items:center;gap:12px;max-width:340px}
  .cortv2 .connector-node{width:100%;padding:20px 16px}
  .cortv2 .connector-node-hub{padding:28px 16px}
  .cortv2 .connector-arrow::before{content:'↓'}
}
@media(max-width:768px){
  .cortv2 .events-grid{grid-template-columns:1fr}
  .cortv2 .tier-grid{grid-template-columns:1fr;max-width:400px}
  .cortv2 .product-inner{grid-template-columns:1fr;gap:40px}
}
@media(max-width:520px){.cortv2 .pillars-grid{grid-template-columns:1fr}}
@media(max-width:400px){.cortv2 .member-card{padding:20px 22px;transform:rotate(0)}}
/* CØRT Play */
.cortv2 .cort-play{background:var(--bg);padding:88px 24px;border-bottom:1.5px solid var(--border)}
.cortv2 .cort-play-inner{max-width:1000px;margin:0 auto;text-align:center}
.cortv2 .cort-play-lead{max-width:600px;margin:-34px auto 40px;font-size:15px;color:var(--muted);line-height:1.6}
.cortv2 .play-formats{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-bottom:40px}
.cortv2 .play-format{background:#fff;border:1.5px solid var(--border);border-radius:12px;padding:28px 22px;text-align:left;transition:border-color .15s,box-shadow .15s,transform .15s}
.cortv2 .play-format:hover{border-color:#000;box-shadow:4px 4px 0 #000;transform:translate(-2px,-2px)}
.cortv2 .play-format-name{font-size:19px;font-weight:900;letter-spacing:-.02em;color:#000;margin-bottom:8px}
.cortv2 .play-format-desc{font-size:13px;color:var(--muted);line-height:1.55}
/* CØRT TV */
.cortv2 .cort-tv{background:#000;padding:88px 24px}
.cortv2 .cort-tv-inner{max-width:1000px;margin:0 auto;display:grid;grid-template-columns:1.05fr .95fr;gap:48px;align-items:center}
.cortv2 .cort-tv-screen{display:flex;flex-direction:column;align-items:center}
.cortv2 .cort-tv-frame{width:100%;aspect-ratio:16/10;background:#0d0d0d;border:1.5px solid var(--accent);border-radius:16px;box-shadow:0 0 34px rgba(255,234,0,.22),0 0 90px rgba(255,234,0,.08);display:flex;align-items:center;justify-content:center;position:relative}
.cortv2 .cort-tv-live{position:absolute;top:16px;left:18px;font-size:11px;font-weight:800;letter-spacing:.14em;text-transform:uppercase;color:var(--accent)}
.cortv2 .cort-tv-brand{font-size:clamp(30px,5vw,46px);font-weight:900;letter-spacing:-.04em;color:#fff}
.cortv2 .cort-tv-brand span{display:inline-block;width:9px;height:9px;background:var(--accent);border-radius:50%;margin:0 6px 0 2px;vertical-align:middle}
.cortv2 .cort-tv-stand{width:120px;height:10px;background:#0d0d0d;border:1.5px solid #1a1a1a;border-top:none;border-radius:0 0 10px 10px}
.cortv2 .cort-tv-info{text-align:left}
.cortv2 .cort-tv-title{font-size:clamp(26px,4vw,38px);font-weight:900;letter-spacing:-.03em;color:#fff;line-height:1.1;margin:6px 0 18px}
.cortv2 .cort-tv-desc{background:#0d0d0d;border-left:3px solid var(--accent);border-radius:0 10px 10px 0;padding:16px 18px;font-size:15px;color:#fff;line-height:1.5;margin-bottom:18px}
.cortv2 .cort-tv-desc strong{color:var(--accent)}
.cortv2 .cort-tv-sub{font-size:13.5px;color:rgba(255,255,255,.7);line-height:1.55;margin-bottom:26px}
@media(max-width:768px){.cortv2 .play-formats{grid-template-columns:1fr}.cortv2 .cort-tv-inner{grid-template-columns:1fr;gap:32px}.cortv2 .cort-tv-info{text-align:center}.cortv2 .cort-tv-desc{text-align:left}}
/* Featured products */
.cortv2 .featured{background:var(--bg);padding:88px 24px}
.cortv2 .featured-grid{max-width:1080px;margin:0 auto;display:grid;grid-template-columns:repeat(3,1fr);gap:16px}
.cortv2 .featured-card{background:#fff;border:1.5px solid var(--border);border-radius:14px;overflow:hidden;display:flex;flex-direction:column;text-decoration:none;color:inherit;transition:border-color .15s,box-shadow .15s,transform .15s}
.cortv2 .featured-card:hover{border-color:#000;box-shadow:4px 4px 0 #000;transform:translate(-2px,-2px)}
.cortv2 .featured-media{position:relative;aspect-ratio:4/3;background:#0d0d0d;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:14px}
.cortv2 .featured-media-mark{width:60px;height:60px;opacity:.35}
.cortv2 .featured-media-label{font-size:10.5px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,.5)}
.cortv2 .featured-body{padding:22px 22px 24px;display:flex;flex-direction:column;flex:1}
.cortv2 .featured-live{display:inline-flex;align-items:center;gap:7px;align-self:flex-start;font-size:10.5px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--muted);margin-bottom:12px}
.cortv2 .featured-name{font-size:20px;font-weight:900;letter-spacing:-.02em;color:#000;margin-bottom:8px}
.cortv2 .featured-desc{font-size:13.5px;color:var(--muted);line-height:1.55;margin-bottom:20px}
.cortv2 .featured-foot{margin-top:auto;display:flex;align-items:center;justify-content:space-between;padding-top:16px;border-top:1px solid var(--border)}
.cortv2 .featured-price{font-size:12px;font-weight:800;letter-spacing:.05em;text-transform:uppercase;color:var(--muted)}
.cortv2 .featured-cta{font-size:14px;font-weight:800;color:#000}
@media(max-width:768px){.cortv2 .featured-grid{grid-template-columns:1fr;max-width:420px}}
